query GetOrders($status: OrderStatus, $page: Int) {
  orders(status: $status, page: $page) {
    data { id status createdAt customer { name } totalAmount }
    pagination { page totalItems hasNext }
  }
}

query GetOrder($id: ID!) {
  order(id: $id) {
    id status createdAt
    customer { name phone }
    items { id name quantity unitPrice }
    totalAmount currency
  }
}

mutation ConfirmOrder($id: ID!, $input: ConfirmOrderInput!) {
  confirmOrder(id: $id, input: $input) {
    id status estimatedReadyAt
  }
}

mutation UpdateStatus($id: ID!, $input: UpdateStatusInput!) {
  updateOrderStatus(id: $id, input: $input) {
    id status updatedAt
  }
}

mutation CancelOrder($id: ID!, $input: CancelOrderInput!) {
  cancelOrder(id: $id, input: $input) {
    id status cancelledAt
  }
}
